import { computed, makeAutoObservable } from "mobx";

import { clamp, linearScale, nearestArrayIndex } from "./geometry";
import { normalizeSeries } from "./series";
import type { ChartMargins, ForecastCardConfig, ForecastSeries, LaneBounds, MotionMode } from "./types";

const DEFAULT_HEIGHT = 360;
const LANE_ORDER = ["power", "price", "soc", "shadow", "other"] as const;

export class ForecastCardStore {
  hass: { states: Record<string, unknown> } | null = null;
  config: ForecastCardConfig = { type: "custom:haeo-forecast-card" };
  width = 640;
  height = DEFAULT_HEIGHT;
  pointerX: number | null = null;
  pointerY: number | null = null;
  nowMs = Date.now();
  highlightedSeries: string | null = null;

  constructor() {
    makeAutoObservable(this, {
      margins: computed.struct,
      laneSeries: computed.struct,
      laneBounds: computed.struct,
      tooltipRows: computed.struct,
    });
  }

  setHass(hass: { states: Record<string, unknown> }): void {
    this.hass = hass;
  }

  setConfig(config: ForecastCardConfig): void {
    this.config = config;
  }

  setSize(width: number, height: number): void {
    this.width = Math.max(240, width);
    this.height = Math.max(220, height);
  }

  setPointer(x: number | null, y: number | null): void {
    this.pointerX = x;
    this.pointerY = y;
  }

  setNow(nowMs: number): void {
    this.nowMs = nowMs;
  }

  setHighlightedSeries(key: string | null): void {
    this.highlightedSeries = key;
  }

  get motionMode(): MotionMode {
    return this.config.animation_mode ?? "smooth";
  }

  get animationSpeed(): number {
    const raw = this.config.animation_speed ?? 1;
    return clamp(raw, 0.2, 3);
  }

  get chartHeight(): number {
    return this.config.height ?? DEFAULT_HEIGHT;
  }

  get margins(): ChartMargins {
    const compact = this.width < 400;
    return {
      top: 16,
      right: compact ? 10 : 16,
      bottom: compact ? 34 : 40,
      left: compact ? 40 : 54,
    };
  }

  get normalizedSeries(): ForecastSeries[] {
    return normalizeSeries(this.hass as { states: Record<string, unknown> } | null, this.config);
  }

  get hasData(): boolean {
    return this.normalizedSeries.length > 0;
  }

  get laneSeries(): Map<string, ForecastSeries[]> {
    const groups = new Map<string, ForecastSeries[]>();
    for (const lane of LANE_ORDER) {
      groups.set(lane, []);
    }
    for (const series of this.normalizedSeries) {
      if (!groups.has(series.lane)) {
        groups.set(series.lane, []);
      }
      groups.get(series.lane)?.push(series);
    }
    return new Map([...groups.entries()].filter((entry) => entry[1].length > 0));
  }

  get xDomain(): { min: number; max: number; step: number } {
    if (!this.hasData) {
      const now = this.nowMs;
      return { min: now, max: now + 60_000, step: 60_000 };
    }
    const points = this.normalizedSeries[0].points;
    const min = points[0].time;
    const max = points[points.length - 1].time;
    const step = points.length > 1 ? Math.max(1, points[1].time - points[0].time) : 60_000;
    return { min, max, step };
  }

  get animatedOffsetMs(): number {
    if (this.motionMode === "off") {
      return 0;
    }
    const prefersReducedMotion = globalThis.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches ?? false;
    if (this.motionMode === "reduced" || prefersReducedMotion) {
      return 0;
    }
    const { min, step } = this.xDomain;
    const elapsed = (this.nowMs - min) * this.animationSpeed;
    if (elapsed <= 0 || step <= 0) {
      return 0;
    }
    return elapsed % step;
  }

  xScale(time: number): number {
    const { min, max } = this.xDomain;
    const innerWidth = this.width - this.margins.left - this.margins.right;
    return linearScale(time - this.animatedOffsetMs, min, max, this.margins.left, this.margins.left + innerWidth);
  }

  get laneRects(): Map<string, { top: number; bottom: number }> {
    const count = this.laneSeries.size || 1;
    const innerTop = this.margins.top;
    const innerBottom = this.height - this.margins.bottom;
    const laneHeight = (innerBottom - innerTop) / count;
    let laneIndex = 0;
    const result = new Map<string, { top: number; bottom: number }>();
    for (const lane of this.laneSeries.keys()) {
      const top = innerTop + laneIndex * laneHeight;
      result.set(lane, { top, bottom: top + laneHeight });
      laneIndex += 1;
    }
    return result;
  }

  get laneBounds(): Map<string, LaneBounds> {
    const result = new Map<string, LaneBounds>();
    for (const [lane, seriesList] of this.laneSeries.entries()) {
      let min = Number.POSITIVE_INFINITY;
      let max = Number.NEGATIVE_INFINITY;
      for (const series of seriesList) {
        for (let i = 0; i < series.values.length; i += 1) {
          const value = series.values[i];
          min = Math.min(min, value);
          max = Math.max(max, value);
        }
      }
      if (!Number.isFinite(min) || !Number.isFinite(max)) {
        result.set(lane, { min: 0, max: 1 });
        continue;
      }
      if (min === max) {
        const delta = Math.max(1, Math.abs(min) * 0.15);
        result.set(lane, { min: min - delta, max: max + delta });
      } else {
        const padding = Math.max(0.1, (max - min) * 0.08);
        result.set(lane, { min: min - padding, max: max + padding });
      }
    }
    return result;
  }

  yScale(lane: string, value: number): number {
    const bounds = this.laneBounds.get(lane) ?? { min: 0, max: 1 };
    const rect = this.laneRects.get(lane) ?? { top: this.margins.top, bottom: this.height - this.margins.bottom };
    return linearScale(value, bounds.min, bounds.max, rect.bottom, rect.top);
  }

  get hoverTimeMs(): number | null {
    if (this.pointerX === null) {
      return null;
    }
    const x = clamp(this.pointerX, this.margins.left, this.width - this.margins.right);
    const { min, max } = this.xDomain;
    const innerWidth = this.width - this.margins.left - this.margins.right;
    const ratio = innerWidth > 0 ? (x - this.margins.left) / innerWidth : 0;
    return min + ratio * (max - min) + this.animatedOffsetMs;
  }

  get hoverX(): number | null {
    const time = this.hoverTimeMs;
    return time === null ? null : this.xScale(time);
  }

  get tooltipRows(): Array<{ key: string; label: string; value: number; unit: string; color: string }> {
    const time = this.hoverTimeMs;
    if (time === null) {
      return [];
    }
    const rows: Array<{ key: string; label: string; value: number; unit: string; color: string }> = [];
    for (const series of this.normalizedSeries) {
      const idx = nearestArrayIndex(series.times, time);
      rows.push({
        key: series.key,
        label: series.label,
        value: series.values[idx],
        unit: series.unit,
        color: series.color,
      });
    }
    return rows.sort((a, b) => b.value - a.value);
  }

  get tooltipTotals(): Array<{ lane: string; value: number; unit: string }> {
    const time = this.hoverTimeMs;
    if (time === null) {
      return [];
    }
    const totals = new Map<string, { value: number; unit: string }>();
    for (const series of this.normalizedSeries) {
      const idx = nearestArrayIndex(series.times, time);
      const existing = totals.get(series.lane) ?? { value: 0, unit: series.unit };
      totals.set(series.lane, {
        value: existing.value + series.values[idx],
        unit: existing.unit || series.unit,
      });
    }
    return [...totals.entries()].map(([lane, total]) => ({
      lane,
      value: total.value,
      unit: total.unit,
    }));
  }
}
